    ('cat_soft_doll_or_teddy_care_play', 2, 2, 'visible', true, true, 'Best for simple soft cuddles', 'My First Baby Girl Doll', 'John Lewis', 'John Lewis', 'https://www.johnlewis.com/john-lewis-my-first-baby-girl-doll/p5740683', NULL, '£12.50', 'in_stock', '2 years', 'A soft squeezable first baby doll with a onesie and hat, easy to hold and cuddle for feeding, carrying and bedtime pretend without electronic sounds or extra gadgets.', 'Sometimes the best care play is quiet: wrap, carry, pat to sleep, no buttons required. A soft first doll leaves room for their own story. Simple soft cuddles when you want nurturing pretend to grow from imagination, and electronic dolls already bring too much noise into the house.', 'Its soft body and simple design make it perfect for toddlers to hold and cuddle, fostering early nurturing instincts and care play.', 'No extra accessories included.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', 'Warning! Choking hazard - due to small parts that may cause a choking hazard, Warning! Not suitable for children under 2 years (despite age suitable from 2 years).', 'good', ARRAY['https://www.johnlewis.com/john-lewis-my-first-baby-girl-doll/p5740683', 'https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_safety'),
    ('cat_soft_doll_or_teddy_care_play', 3, 5, 'visible', true, true, 'Best for several care sounds', 'Mon Grand Poupon Chérie', 'Corolle', 'Amazon UK', 'https://www.nytimes.com/wirecutter/out/link/76051/228653/4/236094?merchant=Amazon', NULL, '£73', 'in_stock', '2 years plus', 'A premium Corolle Mon Grand Poupon Chérie interactive doll with a soft vanilla scent and several care sounds including giggles, kisses, burps and sleep cues for richer pretend.', 'Richer care sequences need more than one sound cue once pretend worlds get bigger. Several gentle responses keep feed, burp and settle play going. Several care sounds for families ready for a premium soft doll, when the budget allows and they already enjoy longer nurturing scenes.', 'Its interactive functions and realistic sounds provide a rich platform for nurturing and care narratives, encouraging more elaborate pretend play beyond basic cuddling.', 'Higher price point. Requires batteries (not included).', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'good', ARRAY['https://www.nytimes.com/wirecutter/reviews/best-dolls/', 'https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_price'),
    ('cat_soft_doll_or_teddy_care_play', 4, 4, 'visible', true, true, 'Best for weighted newborn care', 'Doll in Pink Bunny Outfit', 'Tiny Treasures', 'Argos', 'https://www.argos.co.uk/product/7469107', NULL, '£40', 'in_stock', '3 years plus', 'A realistic soft doll with a weighted body, lifelike face and newborn scent details, often paired with a birth certificate style keepsake for carrying and care pretend play.', 'A little weight in the arms makes carrying and settling feel closer to looking after someone smaller. Lifelike details invite careful wrapping and feeding scenes. Weighted newborn care when they are ready for slower, more serious pretend, and you are happy with a realistic look rather than a cartoon soft toy.', 'The weighted body and realistic features provide an authentic caregiving experience, fostering nurturing play and emotional development.', 'Not interactive. Long hair may not appeal to all.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'strong', ARRAY['https://www.mumsnet.com/swearsby/best-dolls']::text[], 'check_url'),
    ('cat_soft_doll_or_teddy_care_play', 5, 11, 'visible', true, true, 'Best for doll meal extras', 'Baby Doll Feed & Care Set', 'Ivy & Lily', 'Smyths Toys UK', 'https://www.smythstoys.com/uk/en-gb/brand/ivy-and-lily/ivy-and-lily-baby-doll-feed-and-care-set/p/248209', NULL, '£7.99', 'in_stock', '2 Years +', 'A pastel feed and care accessory set with sippy cup, bowl and spoon sized for doll play, so your child can run mealtime routines with a soft doll they already own.', 'Accessories stretch care play when a soft doll is already loved. Cup, bowl and spoon turn “feed the baby” into a clear little mealtime scene. Doll meal extras when you would rather deepen pretend worlds than buy another doll, and mealtime care is the story they keep returning to.', 'The focus on feeding and care accessories directly promotes nurturing play, aligning with the stage shift towards comfort and care narratives.', 'Doll sold separately.', 'buy', true, 'Thoughtful if age-fit and not already owned.', 'High chance the family owns a version already. Look for the stage shift: a version that adds clearer turns, richer pretend play, more control or easier setup rather than simply more of the same.', NULL, 'emerging', ARRAY['https://www.smythstoys.com/uk/en-gb/brand/ivy-and-lily/ivy-and-lily-baby-doll-feed-and-care-set/p/248209']::text[], 'check_url')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '31-33m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-23T19:56:06.521Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '31-33m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

